static void trim(char *s) {
    size_t n = strlen(s);
    while (n > 0 && (s[n - 1] == '\n' || s[n - 1] == '\r' || s[n - 1] == ' ')) {
        s[--n] = '\0';
    }
}

int case_load(const char *path, CaseSpec *spec) {
    FILE *fp = fopen(path, "r");
    char line[512];
    if (!fp) {
        return -1;
    }
    memset(spec, 0, sizeof(*spec));
    for (int i = 0; i < MAX_BLOCKS; i++) {
        spec->perm[i] = i;
    }
